import React, { useState } from 'react';
import { Card, CardContent, CardDescription, CardHeader, CardTitle } from '../components/ui/card';
import { Button } from '../components/ui/button';
import { Badge } from '../components/ui/badge';
import { Switch } from '../components/ui/switch';
import { Clock, Calendar, Plus, Edit, Trash2 } from 'lucide-react';

export default function DoctorAvailability() {
  const [isAvailable, setIsAvailable] = useState(true);

  const schedule = [
    { day: 'Monday', start: '9:00 AM', end: '5:00 PM', enabled: true },
    { day: 'Tuesday', start: '9:00 AM', end: '5:00 PM', enabled: true },
    { day: 'Wednesday', start: '9:00 AM', end: '5:00 PM', enabled: true },
    { day: 'Thursday', start: '9:00 AM', end: '5:00 PM', enabled: true },
    { day: 'Friday', start: '9:00 AM', end: '3:00 PM', enabled: true },
    { day: 'Saturday', start: '10:00 AM', end: '2:00 PM', enabled: false },
    { day: 'Sunday', start: 'Off', end: '', enabled: false }
  ];

  return (
    <div className="space-y-6">
      <div>
        <h1 className="text-3xl font-bold">Doctor Availability</h1>
        <p className="text-muted-foreground">Manage your working hours and availability</p>
      </div>

      {/* Quick Status */}
      <Card>
        <CardHeader>
          <CardTitle className="flex items-center justify-between">
            <span className="flex items-center gap-2">
              <Clock className="w-5 h-5" />
              Current Status
            </span>
            <Switch
              checked={isAvailable}
              onCheckedChange={setIsAvailable}
            />
          </CardTitle>
          <CardDescription>
            Toggle your availability for patient bookings
          </CardDescription>
        </CardHeader>
        <CardContent>
          <div className="flex items-center gap-3">
            <div className={`w-3 h-3 rounded-full ${isAvailable ? 'bg-green-500' : 'bg-red-500'}`}></div>
            <span className="font-medium">
              {isAvailable ? 'Available for appointments' : 'Not accepting new appointments'}
            </span>
          </div>
        </CardContent>
      </Card>

      {/* Weekly Schedule */}
      <Card>
        <CardHeader>
          <CardTitle className="flex items-center gap-2">
            <Calendar className="w-5 h-5" />
            Weekly Schedule
          </CardTitle>
          <CardDescription>
            Set your regular working hours for each day
          </CardDescription>
        </CardHeader>
        <CardContent>
          <div className="space-y-4">
            {schedule.map((day, index) => (
              <div key={index} className="flex items-center justify-between p-4 border border-gray-200 rounded-lg">
                <div className="flex items-center gap-4">
                  <Switch
                    checked={day.enabled}
                    onCheckedChange={() => {}}
                  />
                  <div className="w-24">
                    <span className="font-medium">{day.day}</span>
                  </div>
                  <div className="flex items-center gap-2">
                    {day.enabled ? (
                      <>
                        <Badge variant="outline">{day.start}</Badge>
                        <span className="text-muted-foreground">to</span>
                        <Badge variant="outline">{day.end}</Badge>
                      </>
                    ) : (
                      <Badge variant="secondary">Unavailable</Badge>
                    )}
                  </div>
                </div>
                <div className="flex items-center gap-2">
                  <Button variant="ghost" size="sm">
                    <Edit className="w-4 h-4" />
                  </Button>
                  <Button variant="ghost" size="sm" className="text-red-500 hover:text-red-700">
                    <Trash2 className="w-4 h-4" />
                  </Button>
                </div>
              </div>
            ))}
          </div>
          
          <Button className="mt-4 w-full bg-blue-600 hover:bg-blue-700">
            <Plus className="w-4 h-4 mr-2" />
            Add Special Hours
          </Button>
        </CardContent>
      </Card>

      {/* Upcoming Breaks */}
      <Card>
        <CardHeader>
          <CardTitle>Scheduled Breaks</CardTitle>
          <CardDescription>
            Manage your upcoming time off and breaks
          </CardDescription>
        </CardHeader>
        <CardContent>
          <div className="space-y-4">
            {[
              { date: 'Jan 15, 2025', reason: 'Conference', duration: 'Full day' },
              { date: 'Jan 22, 2025', reason: 'Personal', duration: '2:00 PM - 4:00 PM' }
            ].map((break_, index) => (
              <div key={index} className="flex items-center justify-between p-4 border border-gray-200 rounded-lg">
                <div>
                  <h4 className="font-medium">{break_.reason}</h4>
                  <p className="text-sm text-muted-foreground">
                    {break_.date} • {break_.duration}
                  </p>
                </div>
                <Button variant="ghost" size="sm" className="text-red-500 hover:text-red-700">
                  <Trash2 className="w-4 h-4" />
                </Button>
              </div>
            ))}
            
            {/* Add new break */}
            <Button variant="outline" className="w-full">
              <Plus className="w-4 h-4 mr-2" />
              Schedule Time Off
            </Button>
          </div>
        </CardContent>
      </Card>
    </div>
  );
}